ເຫຕທີ່ເຮັດໃຫ້ສະແຫວງຫານິບພານ
ພິກຂຸ ທ. ! ການສະແຫວງຫາຢ່າງປະເສີດ ໔ ຢ່າງເຫຼົ່ານີ້ມີຢູ່. ສີ່ຢ່າງແນວໃດໜໍ ? ສີ່ຢ່າງຄື :-
ພິກຂຸ ທ. ! ໃນກລະນີນີ້ ບຸຄຄົນບາງຄົນ ຕົນເອງເປັນຜູ່ ມີຄວາມແກ່ເປັນທັມມະດາ ຢູ່ ກໍຮູ້ແຈ້ງຊຶ່ງໂທດໃນຄວາມແກ່ເປັນທັມມະດານັ້ນ ແລ້ວສະແຫວງຫານິບພານ ອັນເປັນທັມບໍ່ມີຄວາມແກ່ ອັນເປັນທັມກະເສມຈາກໂຢຄະ ບໍ່ມີອື່ນຍິ່ງກວ່າ ;
ບຸຄຄົນບາງຄົນ ຕົນເອງ ເປັນຜູ່ ມີຄວາມເຈັບໄຂ້ເປັນທັມມະດາ ຢູ່ ກໍຮູ້ແຈ້ງຊຶ່ງໂທດໃນຄວາມເຈັບໄຂ້ເປັນທັມມະດານັ້ນ ແລ້ວສະແຫວງຫານິບພານ ອັນເປັນທັມບໍ່ມີຄວາມເຈັບໄຂ້ ອັນເປັນທັມກະເສມຈາກໂຢຄະ ບໍ່ມີອື່ນຍິ່ງກວ່າ ;
ພາກ ໔ - ມັຄຄະອະຣິຍະສັຈຈ໌ : ຕອນສັມມາທິຕຖິ          ໙໑໑
ບຸຄຄົນບາງຄົນ ຕົນເອງເປັນຜູ່ ມີຄວາມຕາຍເປັນທັມມະດາ ຢູ່ ກໍຮູ້ແຈ້ງຊຶ່ງໂທດໃນຄວາມຕາຍເປັນທັມມະດານັ້ນ ແລ້ວສະແຫວງຫານິບພານ ອັນເປັນທັມບໍ່ມີຄວາມຕາຍ ອັນເປັນທັມກະເສມຈາກໂຢຄະ ບໍ່ມີອື່ນຍິ່ງກວ່າ ;

ພິກຂຸ ທ. ! ພິກຂຸນັ້ນໜໍ ມີຄວາມເຄົາລົບ ມີຄວາມຢໍາເກງ ມີຄວາມປະພຶຕເຂົ້າກັນໄດ້ ໃນເພື່ອນສະພຣົມມະຈາຣີທັງຫຼາຍ ຈັກບໍາເພັນ ອະພິສະມາຈາຣິກະທັມ ໃຫ້ບໍຣິບູນໄດ້ ດັ່ງນີ້ນັ້ນ ນັ້ນເປັນຖານະທີ່ຈະມີໄດ້ ; ເມື່ອບໍາເພັນອະພິສະມາຈາຣິກະທັມໃຫ້ບໍຣິບູນແລ້ວ ຈັກບໍາເພັນເສຂະທັມໃຫ້ບໍຣິບູນໄດ້ ດັ່ງນີ້ນັ້ນ ນັ້ນເປັນຖານະທີ່ຈະມີໄດ້ ; ເມື່ອບໍາເພັນເສຂະທັມໃຫ້ບໍຣິບູນແລ້ວ ຈັກບໍາເພັນ ສີລະຂັນທ໌ ໃຫ້ບໍຣິບູນໄດ້ ດັ່ງນີ້ນັ້ນ ນັ້ນເປັນຖານະທີ່ຈະມີໄດ້ ; ເມື່ອບໍາເພັນສີລະຂັນທ໌ໃຫ້ບໍຣິບູນແລ້ວ ຈັກບໍາເພັນ ສະມາທິຂັນທ໌ ໃຫ້ບໍຣິບູນໄດ້ ດັ່ງນີ້ນັ້ນ ນັ້ນເປັນຖານະທີ່ຈະມີໄດ້ ; ເມື່ອບໍາເພັນສະມາທິຂັນທ໌ໃຫ້ບໍຣິບູນແລ້ວ ຈັກບໍາເພັນ ປັນຍາຂັນທ໌ ໃຫ້ບໍຣິບູນໄດ້ ດັ່ງນີ້ນັ້ນ ນັ້ນເປັນຖານະທີ່ຈະມີໄດ້.
- ປັນຈກ. ອັງ. ໒໒/໑໖/໒໒.
ສິ່ງສົງເຄາະສັມມາທິຕຖິໃຫ້ອອກຜົລ
ພິກຂຸ ທ. ! ສັມມາທິຕຖິ ອັນອົງທັມ ໕ ປະການ ອະນຸເຄາະແລ້ວ ຍ່ອມມີເຈໂຕວິມຸຕຕິ ເປັນຜົລ ເປັນອານິສົງສ໌ ແລະ ມີປັນຍາວິມຸຕຕິເປັນຜົລ ເປັນອານິສົງສ໌.
ຫ້າປະການເຫຼົ່າໃດໜໍ ? ຫ້າປະການຄື : ພິກຂຸ ທ. ! ໃນກໍລະນີນີ້ :
ສັມມາທິຕຖິ	ເປັນທັມອັນ	ສີລ ອະນຸເຄາະແລ້ວ ;
ສັມມາທິຕຖິ	ເປັນທັມອັນ	ສູຕ໑ ອະນຸເຄາະແລ້ວ ;
ສັມມາທິຕຖິ	ເປັນທັມອັນ	ສາກັຈສາ໒ ອະນຸເຄາະແລ້ວ ;
ສັມມາທິຕຖິ	ເປັນທັມອັນ	ສະມາຖະ ອະນຸເຄາະແລ້ວ ;
ສັມມາທິຕຖິ	ເປັນທັມອັນ	ວິປັສສະນາ ອະນຸເຄາະແລ້ວ ;
໑. ສູຕ ມາຈາກບາລີ ສຸຕຕະ ໝາຍເຖິງແນວທັມ ຫຼື ຫຼັກທັມທີ່ຈັດເປັນລະບົບໜຶ່ງໆ.
໒. ສາກັຈສາ ຄືການສົນທະນາທັມເພື່ອຕີຄວາມໝາຍແຫ່ງທັມໃຫ້ແຈ່ມແຈ້ງຄັກແນ່.
ພາກ ໔ - ມັຄຄະອະຣິຍະສັຈຈ໌ : ຕອນສັມມາທິຕຖິ          ໙໒໑
ພິກຂຸ ທ. ! ສັມມາທິຕຖິ ອັນອົງທັມ ໕ ປະການເຫຼົ່ານີ້ແລ ອະນຸເຄາະແລ້ວ ຍ່ອມມີເຈໂຕວິມຸຕຕິເປັນຜົລ ເປັນອານິສົງສ໌ ແລະມີປັນຍາວິມຸຕຕິເປັນຜົລ ເປັນອານິສົງສ໌.
- ປັນຈກ. ອັງ. ໒໒/໒໒/໒໕.
ເຫຕປັຈຈັຍແຫ່ງວິຊຊາ ແລະ ວິມຸຕຕິ
ພິກຂຸ ທ. ! ການຄົບສັບບຸຣຸສ ເປັນໄປບໍຣິບູນແລ້ວ ຍ່ອມເຮັດການຟັງສັດທັມໃຫ້ບໍຣິບູນ ;
ການຟັງສັດທັມ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດສັດທາໃຫ້ບໍຣິບູນ ;
ສັດທາ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດໂຢນິໂສມະນະສິກາຣະໃຫ້ບໍຣິບູນ ;
ໂຢນິໂສມະນະສິກາຣະ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດຄວາມເປັນຜູ່ມີສະຕິສັມປະຊັນຍະ
ໃຫ້ບໍຣິບູນ ;
ຄວາມເປັນຜູ່ມີສະຕິສັມປະຊັນຍະ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດການສັງລວມອິນຊີໃຫ້
ບໍຣິບູນ ;
ການສັງລວມອິນຊີ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດສຸຈະຣິຕ ໓ ປະການ ໃຫ້ບໍຣິບູນ ;
ສຸຈະຣິຕ ໓ ປະການ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດສະຕິປັຕຖານ ໔ ປະການໃຫ້ບໍຣິບູນ ;
ສະຕິປັຕຖານ ໔ ປະການ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດໂພຊຊົງຄ໌ ໗ ປະການໃຫ້ບໍຣິບູນ ;
ໂພຊຊົງຄ໌ ໗ ປະການ ບໍຣິບູນແລ້ວ ຍ່ອມເຮັດໃຫ້ວິຊຊາ ແລະວິມຸຕຕິ ໃຫ້ບໍຣິບູນ ;
ພິກຂຸ ທ. ! ອາຫາຣແຫ່ງວິຊຊາ ແລະ ວິມຸຕຕິນີ້ ຍ່ອມມີໄດ້ ດ້ວຍອາການດັ່ງນີ້ ແລະ ບໍຣິບູນແລ້ວ ດ້ວຍອາການດັ່ງນີ້.
(ຕໍ່ຈາກນີ້ ຕຣັດອຸປະມາດ້ວຍຝົນຕົກລົງໃນບ່ອນສູງແລ້ວ ໄຫຼລົງມາໃນບ່ອນຕໍ່າ ຍ່ອມເຮັດໃຫ້ເຕັມບໍລິບູນຕໍ່ໆກັນລົງມາຕາມລະດັບ ຈົນວ່າເຖິງທະເລ).
